queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?navigation_systems a :Navigation_Systems .
    ?navigation_systems p:TypeOfSystem ?typeofsystem .
    BIND(?typeofsystem AS ?o0)
  }
  UNION
  {
    ?communication_systems a :Communication_Systems .
    ?communication_systems p:TypeOfSystem ?typeofsystem .
    ?communication_systems p:Airport ?airport_f .
    FILTER(STR(?airport_f) = "Heathrow")
    BIND(?typeofsystem AS ?o0)
  }
}

